package com.example.documentviewer;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.webkit.MimeTypeMap;
import android.widget.ImageView;
import android.widget.Toast;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class DocumentViewerActivity extends AppCompatActivity {

    private ImageView imageView;
    private PdfRendererView pdfRendererView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null || !Intent.ACTION_VIEW.equals(intent.getAction())) {
            finish();
            return;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            finish();
            return;
        }

        String mimeType = getContentResolver().getType(uri);
        if (mimeType == null) {
            mimeType = guessMimeType(uri);
        }

        if (mimeType != null && mimeType.startsWith("image/")) {
            showImage(uri);
        } else if ("application/pdf".equalsIgnoreCase(mimeType) || isPdfUri(uri)) {
            showPdf(uri);
        } else {
            Toast.makeText(this, "Unsupported document type", Toast.LENGTH_SHORT).show();
            finish();
        }
    }

    private void showImage(Uri uri) {
        setContentView(R.layout.activity_document_image);
        imageView = findViewById(R.id.imageView);
        if (imageView != null) {
            imageView.setImageURI(uri);
        }
    }

    private void showPdf(Uri uri) {
        setContentView(R.layout.activity_document_pdf);
        pdfRendererView = findViewById(R.id.pdfRendererView);
        if (pdfRendererView != null) {
            pdfRendererView.loadDocument(uri);
        } else {
            Toast.makeText(this, "PDF viewer not available", Toast.LENGTH_SHORT).show();
            finish();
        }
    }

    private boolean isPdfUri(Uri uri) {
        String path = uri.getLastPathSegment();
        return path != null && path.toLowerCase().endsWith(".pdf");
    }

    private String guessMimeType(Uri uri) {
        String path = uri.getLastPathSegment();
        if (path == null) return null;
        String extension = MimeTypeMap.getFileExtensionFromUrl(path);
        if (extension == null) return null;
        return MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension.toLowerCase());
    }
}

package com.example.documentviewer;

import android.content.Context;
import android.graphics.pdf.PdfRenderer;
import android.net.Uri;
import android.os.ParcelFileDescriptor;
import android.util.AttributeSet;
import android.view.LayoutInflater;
import android.widget.FrameLayout;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

import java.io.IOException;

public class PdfRendererView extends FrameLayout {

    private ParcelFileDescriptor parcelFileDescriptor;
    private PdfRenderer pdfRenderer;

    public PdfRendererView(@NonNull Context context) {
        super(context);
        init(context);
    }

    public PdfRendererView(@NonNull Context context, @Nullable AttributeSet attrs) {
        super(context, attrs);
        init(context);
    }

    public PdfRendererView(@NonNull Context context, @Nullable AttributeSet attrs, int defStyleAttr) {
        super(context, attrs, defStyleAttr);
        init(context);
    }

    private void init(Context context) {
        LayoutInflater.from(context).inflate(R.layout.view_pdf_renderer, this, true);
    }

    public void loadDocument(Uri uri) {
        release();
        try {
            parcelFileDescriptor = getContext().getContentResolver().openFileDescriptor(uri, "r");
            if (parcelFileDescriptor == null) return;
            pdfRenderer = new PdfRenderer(parcelFileDescriptor);
        } catch (IOException ignored) {
            release();
        }
    }

    public void release() {
        if (pdfRenderer != null) {
            pdfRenderer.close();
            pdfRenderer = null;
        }
        if (parcelFileDescriptor != null) {
            try {
                parcelFileDescriptor.close();
            } catch (IOException ignored) {
            }
            parcelFileDescriptor = null;
        }
    }
}

